INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('borapostar_gerar_carrossel', 'Gerar carrossel', 'Gera carrossel pro Instagram com texto + slides via BoraPostar.', 'content', '🎨', '{"type": "object", "required": ["topic"], "properties": {"topic": {"type": "string", "description": "Tema/assunto do carrossel"}}}'::jsonb, 'http', E'{"url": "https://xxhixkptbggbjqdmebwc.supabase.co/functions/v1/carousel-api/agent/gerar", "async": {"status_check": {"url": "https://xxhixkptbggbjqdmebwc.supabase.co/functions/v1/carousel-api/agent/slides/{{external_id}}", "method": "GET", "headers": {"X-API-Key": "{{credential.api_key}}"}, "failed_when": "status == error", "result_field": "rendered_slides", "success_when": "status == ready"}, "user_message": "show.. tô gerando teu carrossel agora.. 🎨", "external_id_field": "carousel_id"}, "method": "POST", "headers": {"X-API-Key": "{{credential.api_key}}", "Content-Type": "application/json"}, "timeout_ms": 30000, "body_template": "{\\"topic\\":\\"{{topic}}\\"}"}'::jsonb, 'always', 't', 'borapostar') ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
