INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('buffer_publicar', 'Publicar via Buffer', 'Publica/agenda em YouTube, LinkedIn pessoal/empresa via Buffer.', 'publishing', '📨', '{"type": "object", "required": ["text", "channel"], "properties": {"text": {"type": "string"}, "channel": {"enum": ["youtube", "linkedin_personal", "linkedin_company"], "type": "string"}, "schedule_iso": {"type": "string"}}}'::jsonb, 'http', E'{"url": "https://api.buffer.com/graphql", "method": "POST", "headers": {"User-Agent": "Mozilla/5.0", "Content-Type": "application/json", "Authorization": "Bearer {{credential.api_key}}"}, "timeout_ms": 60000, "body_template": "{\\"query\\":\\"mutation { createPost(input: { text: \\\\\\"{{text}}\\\\\\", channelId: \\\\\\"PLACEHOLDER\\\\\\", schedulingType: automatic, mode: addToQueue }) { id } }\\"}"}'::jsonb, 'with_approval', 't', 'buffer') ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
