INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('change_stage', 'Mudar stage do deal', 'Move deal pra outra stage. Guard contra regressao.', 'sales', '➡️', '{"type": "object", "required": ["stage_name"], "properties": {"reason": {"type": "string"}, "stage_name": {"type": "string"}, "allow_regression": {"type": "boolean", "default": false}}}'::jsonb, 'sql', '{"function": "agent_change_stage", "params_map": {"p_reason": "{{reason}}", "p_deal_id": "{{deal_id}}", "p_agent_id": "{{agent_id}}", "p_session_id": "{{session_id}}", "p_stage_name": "{{stage_name}}", "p_allow_regression": "{{allow_regression}}"}}'::jsonb, 'always', 't', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
