INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('criar_deal', 'Criar oportunidade (deal)', 'Cria uma oportunidade (deal) pra um lead que JÁ existe. Use quando um lead existente vira uma nova negociação.', 'crm', '💰', '{"type": "object", "required": ["lead_id"], "properties": {"title": {"type": "string", "description": "Título da oportunidade"}, "value": {"type": "number", "description": "Valor estimado em R$"}, "lead_id": {"type": "string", "description": "UUID do lead (de my_deals ou execute_sql)"}}}'::jsonb, 'sql', '{"function": "agent_create_deal", "params_map": {"p_title": "{{title}}", "p_value": "{{value}}", "p_lead_id": "{{lead_id}}", "p_user_id": "{{user_id}}", "p_agent_id": "{{agent_id}}"}}'::jsonb, 'always', 'f', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('criar_lead', 'Criar lead no CRM', 'Cria um lead novo no CRM. Por padrão já cria um deal (oportunidade) junto no pipeline padrão — igual quando chega um contato novo. Use quando aparecer um contato/interessado que ainda não está no CRM.', 'crm', '🧲', '{"type": "object", "required": ["name"], "properties": {"name": {"type": "string", "description": "Nome do lead"}, "email": {"type": "string"}, "phone": {"type": "string", "description": "Telefone (DDI+DDD+num)"}, "source": {"type": "string", "description": "Origem (ex: indicação, whatsapp, evento)"}, "deal_title": {"type": "string", "description": "Título do deal (opcional)"}, "create_deal": {"type": "boolean", "description": "Criar oportunidade junto (default true)"}}}'::jsonb, 'sql', '{"function": "agent_create_lead", "params_map": {"p_name": "{{name}}", "p_email": "{{email}}", "p_phone": "{{phone}}", "p_source": "{{source}}", "p_user_id": "{{user_id}}", "p_agent_id": "{{agent_id}}", "p_deal_title": "{{deal_title}}", "p_create_deal": "{{create_deal}}"}}'::jsonb, 'always', 'f', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('criar_tarefa', 'Criar tarefa no CRM', 'Cria uma tarefa REAL no CRM (aparece pra equipe, com responsável e prazo). Use quando algo precisa virar pendência rastreável — não é memória interna, é tarefa do sistema. Pra anotação pessoal sua, use salvar_nota.', 'crm', '📋', '{"type": "object", "required": ["name"], "properties": {"name": {"type": "string", "description": "Título da tarefa"}, "due_at": {"type": "string", "description": "Prazo ISO com timezone BR (ex 2026-06-12T09:00:00-03:00)"}, "priority": {"enum": ["low", "medium", "high"], "type": "string", "description": "Prioridade"}, "description": {"type": "string", "description": "Detalhes"}, "responsavel_id": {"type": "string", "description": "UUID do membro responsável (opcional; pega de team_roster)"}}}'::jsonb, 'sql', '{"function": "agent_create_task", "params_map": {"p_name": "{{name}}", "p_due_at": "{{due_at}}", "p_user_id": "{{user_id}}", "p_agent_id": "{{agent_id}}", "p_priority": "{{priority}}", "p_description": "{{description}}", "p_responsavel_id": "{{responsavel_id}}"}}'::jsonb, 'always', 'f', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
