INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('execute_sql', 'Executar SELECT', 'Roda SELECT (read-only) com auto-LIMIT 1000 e statement_timeout 30s. Bloqueado: INSERT/UPDATE/DELETE/DROP e tabelas sensíveis.', 'admin', '⚡', '{"type": "object", "required": ["sql"], "properties": {"sql": {"type": "string", "description": "Query SELECT/WITH apenas. Não use ; no meio."}}}'::jsonb, 'sql', '{"function": "agent_execute_readonly", "params_map": {"p_sql": "{{sql}}", "p_user_id": "{{user_id}}"}}'::jsonb, 'always', 't', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
