INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('team_roster', 'Lista do time (nome + telefone)', 'Retorna os membros ativos do time com nome e telefone. Use pra descobrir o telefone de quem você precisa MARCAR (@menção) no grupo, ou cruzar o responsável de uma pendência com o telefone dele. Não expõe email nem dados sensíveis.', 'crm', '👥', '{"type": "object", "properties": {}}'::jsonb, 'sql', '{"function": "agent_team_roster", "params_map": {}}'::jsonb, 'always', 'f', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('uazapi_listar_grupos', 'Listar grupos do WhatsApp (UAZAPI)', 'Lista todos os grupos de WhatsApp da instância conectada (a credencial UAZAPI define a instância). Retorna nome + id (JID @g.us) de cada grupo. Use pra DESCOBRIR o id do grupo que você precisa antes de enviar mensagem. Fluxo: liste os grupos → mostre os nomes pro usuário → ele escolhe → guarde o id com salvar_nota (título "grupo-do-time") → use esse id no number do uazapi_whatsapp_text.', 'tool', '👥', '{"type": "object", "properties": {}}'::jsonb, 'http', '{"url": "{{credential.base_url}}/group/list", "method": "GET", "headers": {"token": "{{credential.api_key}}"}, "timeout_ms": 30000}'::jsonb, 'always', 'f', 'uazapi') ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('uazapi_whatsapp_text', 'Enviar WhatsApp (UAZAPI)', 'Envia mensagem de texto via UAZAPI. Funciona pra DM (número individual) OU grupo. Em grupo, pode MARCAR pessoas (@menção).
INSERT INTO public.agents_skill_catalog (slug, display_name, description, category, emoji, parameters_schema, action_type, action_config, default_usage_mode, is_recommended, provider) VALUES ('update_lead', 'Atualizar lead', 'Atualiza campos do lead (whitelist).', 'sales', '✏️', '{"type": "object", "required": ["patch"], "properties": {"patch": {"type": "object"}, "reason": {"type": "string"}}}'::jsonb, 'sql', '{"function": "agent_update_lead", "params_map": {"p_patch": "{{patch}}", "p_reason": "{{reason}}", "p_lead_id": "{{lead_id}}", "p_agent_id": "{{agent_id}}", "p_session_id": "{{session_id}}"}}'::jsonb, 'always', 't', NULL) ON CONFLICT (slug) DO UPDATE SET display_name=EXCLUDED.display_name, description=EXCLUDED.description, parameters_schema=EXCLUDED.parameters_schema, action_config=EXCLUDED.action_config, action_type=EXCLUDED.action_type;
